1	type Heading = "N" | "E" | "S" | "W";
2	
3	const ROTATIONS: Record<"L" | "R", Record<Heading, Heading>> = {
4	  L: { N: "W", W: "S", S: "E", E: "N" },
5	  R: { N: "E", E: "S", S: "W", W: "N" },
6	};
7	const FORWARD_DELTA: Record<Heading, [number, number]> = {
8	  N: [0, 1],
9	  E: [1, 0],
10	  S: [0, -1],
11	  W: [-1, 0],
12	};
13	
14	export function execute(commands: string): string {
15	  let x = 0;
16	  let y = 0;
17	  let heading: Heading = "N";
18	  for (const command of commands) {
19	    if (command === "F") {
20	      const [dx, dy] = FORWARD_DELTA[heading];
21	      x += dx;
22	      y += dy;
23	    } else if (command === "L" || command === "R") {
24	      heading = ROTATIONS[command][heading];
25	    }
26	  }
27	  return `${x}:${y}:${heading}`;
28	}
